// Parse Claude response into individual signals
const response = $input.first().json;
let text = '';

if (response.content && Array.isArray(response.content)) {
  text = response.content
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('\n');
}

let parsed;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  // Try to find JSON object in the response
  const match = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse signals: ' + e.message, raw: text } }];
}

if (!parsed.signals || !parsed.signals.length) {
  return [{ json: { error: 'No signals found', raw: text } }];
}

// Return each signal as a separate item for looping
return parsed.signals.map(signal => ({ json: signal }));

// Parse qualification result and merge with original signal
const response = $input.first().json;
const signal = $('Parse Signals').item.json;

let text = '';
if (response.content && Array.isArray(response.content)) {
  text = response.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
}

let qual;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  qual = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  qual = { qualified: false, hard_disqualifier: 'Parse error', total_score: 0 };
}

return [{
  json: {
    // Signal data
    company: signal.company,
    role_title: signal.role_title,
    location: signal.location,
    num_openings: signal.num_openings,
    job_url: signal.job_url || '',
    industry: signal.industry,
    signal_strength: signal.signal_strength,
    // Qualification data
    total_score: qual.total_score || 0,
    qualified: qual.qualified === true && !qual.hard_disqualifier && (qual.total_score || 0) >= 6,
    hard_disqualifier: qual.hard_disqualifier || null,
    employees: qual.employees || 'unknown',
    revenue: qual.revenue || 'unknown',
    has_existing_ai_voice: qual.has_existing_ai_voice || false,
    existing_solution: qual.existing_solution || 'none',
    estimated_contract_value: qual.estimated_contract_value || '$100K',
    phone_infrastructure: qual.phone_infrastructure || 'unknown',
    reasoning: qual.reasoning || '',
    scores: qual.scores || {},
    timestamp: new Date().toISOString()
  }
}];

// Prepare deal creation payload with the company ID
const companyId = $('HubSpot: Create Company').item.json.id;
const data = $('Parse Qualification').item.json;

return [{ json: { companyId, ...data } }];

